fun solve(nums: Array<Long>, k: Long): Long {
    val prefixSum = mutableListOf<Long>()
    var sum = 0L
    for (num in nums) {
        sum += num
        prefixSum.add(sum)
    }

    val modMap = mutableMapOf<Long, Int>()
    modMap[0L] = -1

    for (i in prefixSum.indices) {
        val mod = prefixSum[i] % k
        if (modMap.containsKey(mod)) {
            val prevIndex = modMap[mod]!!
            if (i - prevIndex > 0) {
                // We can remove the subarray from prevIndex + 1 to i
                // So we can ignore the elements in this range
                // We need to keep track of the minimum sum
                val currentSum = prefixSum[i] - prefixSum[prevIndex]
                if (currentSum <= 0) {
                    // If the sum is zero or negative, we can remove it
                    // So we can ignore this part and continue
                    continue
                }
            }
        }
        modMap[mod] = i
    }

    // The minimum possible sum is the minimum of all prefix sums that cannot be removed
    var minSum = Long.MAX_VALUE
    for (sum in prefixSum) {
        if (sum < minSum) {
            minSum = sum
        }
    }

    return minSum
}
